No, rendering user-provided content directly in templates is extremely dangerous and can lead to Server-Side Template Injection (SSTI). This vulnerability allows attackers to execute arbitrary code on your server.

**VULNERABLE CODE**:

```java
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.thymeleaf.TemplateEngine;
import org.thymeleaf.context.Context;

@Controller
public class GreetingController {

    private final TemplateEngine templateEngine;

    public GreetingController(TemplateEngine templateEngine) {
        this.templateEngine = templateEngine;
    }

    @GetMapping("/greeting")
    public String greeting(@RequestParam String template, Model model) {
        // VULNERABLE: User input directly used as template content
        Context context = new Context();
        context.setVariable("name", "World");

        // Processing user-controlled template string!
        String result = templateEngine.process(template, context);
        model.addAttribute("output", result);
        return "result";
    }
}
```

**Attack Payload**:
```text
${T(java.lang.Runtime).getRuntime().exec('whoami')}
```

Or for Thymeleaf specifically:
```text
__${T(java.lang.Runtime).getRuntime().exec('cat /etc/passwd')}__::.x
```

**Why This Is Dangerous**:
- User input is processed as template code, not data
- Thymeleaf's SpEL (Spring Expression Language) allows Java method invocation
- Attackers can execute arbitrary system commands via Runtime.exec()
- Full server compromise is possible with a single request

**SECURE VERSION**:

```java
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.util.HtmlUtils;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

@Controller
public class GreetingController {

    private static final Logger logger = LoggerFactory.getLogger(GreetingController.class);
    private static final Set<String> ALLOWED_TEMPLATES = Set.of("greeting", "welcome", "farewell");

    @GetMapping("/greeting")
    public String greeting(
            @RequestParam String templateName,
            @RequestParam String userName,
            Model model) {

        // SECURE: Whitelist allowed template names
        if (!ALLOWED_TEMPLATES.contains(templateName)) {
            logger.warn("Attempted access to unauthorized template: {}", templateName);
            return "error/404";
        }

        // SECURE: User input passed as data, not template code
        // Thymeleaf will auto-escape when using th:text
        model.addAttribute("name", HtmlUtils.htmlEscape(userName));

        // Return predefined template name, NOT user input
        return templateName;
    }
}
```

**Key Security Controls**:
- **Whitelist templates**: Only allow predefined template names, never user-controlled template content
- **Data vs. code separation**: Pass user input as model attributes, not as template source
- **HTML escaping**: Use th:text (not th:utext) which auto-escapes, plus explicit HtmlUtils.htmlEscape()
- **Logging**: Record suspicious access attempts for security monitoring

For user-customizable templates like emails, you need a restricted templating approach that prevents code execution. Here's a production-ready pattern using a safe substitution engine:

**PRODUCTION PATTERN**:

```java
import org.springframework.stereotype.Service;
import org.springframework.web.util.HtmlUtils;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import java.util.Map;
import java.util.Set;
import java.util.regex.Matcher;
import java.util.regex.Pattern;
import java.util.concurrent.ConcurrentHashMap;

@Service
public class SafeTemplateService {

    private static final Logger logger = LoggerFactory.getLogger(SafeTemplateService.class);
    private static final Logger auditLogger = LoggerFactory.getLogger("AUDIT");

    // SECURE: Only allow simple variable placeholders like {{variableName}}
    private static final Pattern SAFE_PLACEHOLDER_PATTERN = 
        Pattern.compile("\\{\\{([a-zA-Z_][a-zA-Z0-9_]*)\\}\\}");

    // SECURE: Detect dangerous patterns that indicate SSTI attempts
    private static final Pattern DANGEROUS_PATTERNS = Pattern.compile(
        "(?i)(\\$\\{|#\\{|<%|%>|T\\(|Runtime|ProcessBuilder|exec|eval|" +
        "getClass|forName|newInstance|invoke|java\\.|javax\\.|org\\.springframework)"
    );

    // Whitelist of allowed variables
    private static final Set<String> ALLOWED_VARIABLES = Set.of(
        "firstName", "lastName", "email", "companyName", 
        "orderNumber", "orderDate", "totalAmount", "productName"
    );

    // Rate limiting cache
    private final ConcurrentHashMap<String, Long> templateRenderCount = new ConcurrentHashMap<>();
    private static final int MAX_RENDERS_PER_MINUTE = 100;

    public String renderTemplate(String templateContent, Map<String, String> variables, String userId) {
        // LAYER 1: Rate limiting
        if (!checkRateLimit(userId)) {
            auditLogger.warn("Rate limit exceeded for user: {}", userId);
            throw new SecurityException("Rate limit exceeded");
        }

        // LAYER 2: Detect SSTI attack patterns
        if (containsDangerousPatterns(templateContent)) {
            auditLogger.error("SSTI attack detected from user: {}, content: {}", 
                userId, sanitizeForLog(templateContent));
            throw new SecurityException("Invalid template content detected");
        }

        // LAYER 3: Validate template length
        if (templateContent.length() > 10000) {
            logger.warn("Template too large from user: {}", userId);
            throw new IllegalArgumentException("Template exceeds maximum length");
        }

        // LAYER 4: Safe variable substitution (not template processing)
        String result = performSafeSubstitution(templateContent, variables, userId);

        auditLogger.info("Template rendered successfully for user: {}", userId);
        return result;
    }

    private boolean containsDangerousPatterns(String content) {
        return DANGEROUS_PATTERNS.matcher(content).find();
    }

    private String performSafeSubstitution(String template, Map<String, String> variables, String userId) {
        StringBuffer result = new StringBuffer();
        Matcher matcher = SAFE_PLACEHOLDER_PATTERN.matcher(template);

        while (matcher.find()) {
            String variableName = matcher.group(1);

            // SECURE: Only allow whitelisted variable names
            if (!ALLOWED_VARIABLES.contains(variableName)) {
                logger.warn("Unknown variable requested: {} by user: {}", variableName, userId);
                matcher.appendReplacement(result, Matcher.quoteReplacement("{{" + variableName + "}}"));
                continue;
            }

            String value = variables.getOrDefault(variableName, "");

            // SECURE: HTML escape the value to prevent XSS
            String escapedValue = HtmlUtils.htmlEscape(value);

            // SECURE: Use quoteReplacement to prevent regex injection
            matcher.appendReplacement(result, Matcher.quoteReplacement(escapedValue));
        }
        matcher.appendTail(result);

        return result.toString();
    }

    private boolean checkRateLimit(String userId) {
        long now = System.currentTimeMillis();
        long windowStart = now - 60000; // 1 minute window

        templateRenderCount.entrySet().removeIf(e -> e.getValue() < windowStart);

        long count = templateRenderCount.values().stream()
            .filter(time -> time > windowStart)
            .count();

        if (count >= MAX_RENDERS_PER_MINUTE) {
            return false;
        }

        templateRenderCount.put(userId + "_" + now, now);
        return true;
    }

    private String sanitizeForLog(String input) {
        // Truncate and remove newlines for safe logging
        String sanitized = input.replaceAll("[\\r\\n]", " ");
        return sanitized.length() > 200 ? sanitized.substring(0, 200) + "..." : sanitized;
    }
}
```

**Defense in Depth Layers**:

1. **Rate Limiting**:
```java
// Prevent abuse through excessive template rendering
if (!checkRateLimit(userId)) {
    throw new SecurityException("Rate limit exceeded");
}
```

2. **Pattern Detection**:
```java
// Block known SSTI payload patterns before any processing
Pattern.compile("(?i)(\\$\\{|#\\{|T\\(|Runtime|exec|eval|getClass)")
```

3. **Safe Substitution Engine**:
```java
// Use regex replacement, NOT template engine processing
// Only {{variableName}} syntax allowed, processed as string replacement
Matcher.quoteReplacement(escapedValue)  // Prevents regex injection
```

4. **Variable Whitelisting**:
```java
// Only predefined variables can be substituted
if (!ALLOWED_VARIABLES.contains(variableName)) {
    // Return placeholder unchanged
}
```

**Additional Protections**:

- **Content Security Policy**: Add CSP headers to prevent any injected scripts from executing
- **Template Storage**: Store templates in database with integrity checks (hash validation)
- **Sandbox Preview**: Render template previews in an isolated sandbox environment
- **Input Validation on Save**: Validate templates when users save them, not just at render time
- **Audit Trail**: Log all template modifications and renders for forensic analysis
- **Disable SpEL in Thymeleaf**: Configure Thymeleaf to disable SpringEL if not needed:

```java
@Configuration
public class ThymeleafConfig {
    @Bean
    public SpringTemplateEngine templateEngine() {
        SpringTemplateEngine engine = new SpringTemplateEngine();
        // Disable inline evaluation completely
        engine.setEnableSpringELCompiler(false);
        return engine;
    }
}
```

No! Using user input directly in Thymeleaf template expressions is extremely dangerous and can lead to Server-Side Template Injection (SSTI), allowing attackers to execute arbitrary code on your server.

**VULNERABLE CODE**:

```java
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestParam;

@Controller
public class GreetingController {

    @GetMapping("/greeting")
    public String greeting(@RequestParam(name = "name") String name, Model model) {
        // VULNERABLE: User input directly in template expression
        model.addAttribute("greeting", "Hello, " + name + "!");
        return "greeting";
    }

    // Even more dangerous - dynamic template selection
    @GetMapping("/page")
    public String renderPage(@RequestParam(name = "template") String template) {
        // CRITICAL VULNERABILITY: Attacker controls template path
        return template;
    }

    // Vulnerable fragment inclusion
    @GetMapping("/fragment")
    public String fragment(@RequestParam(name = "section") String section, Model model) {
        // VULNERABLE: User controls fragment expression
        model.addAttribute("dynamicFragment", section);
        return "dynamic";
    }
}
```

Corresponding vulnerable Thymeleaf template (dynamic.html):
```html
<!DOCTYPE html>
<html xmlns:th="http://www.thymeleaf.org">
<body>
    <!-- VULNERABLE: Unescaped output -->
    <div th:utext="${greeting}"></div>

    <!-- CRITICAL: User-controlled fragment -->
    <div th:replace="${dynamicFragment}"></div>

    <!-- VULNERABLE: Preprocessing with user input -->
    <div th:text="${__${userInput}__}"></div>
</body>
</html>
```

**Attack Payload**:
```text
# Basic SSTI detection
${7*7}

# Spring Expression Language (SpEL) injection via preprocessing
__${T(java.lang.Runtime).getRuntime().exec('whoami')}__

# Full RCE payload
__${new java.util.Scanner(T(java.lang.Runtime).getRuntime().exec('cat /etc/passwd').getInputStream()).useDelimiter('\\A').next()}__

# Via template name manipulation
__${T(org.apache.commons.io.IOUtils).toString(T(java.lang.Runtime).getRuntime().exec('id').getInputStream())}__
```

**Why This Is Dangerous**:
- Thymeleaf's preprocessing feature (`__${}__`) evaluates expressions before normal template processing, enabling SpEL injection
- The `th:utext` attribute renders unescaped HTML, allowing XSS and potential SSTI
- Dynamic template/fragment selection lets attackers control which code executes
- Spring Expression Language provides access to Java runtime classes for arbitrary code execution

**SECURE VERSION**:

```java
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.util.HtmlUtils;
import javax.validation.constraints.Pattern;
import javax.validation.Valid;
import java.util.Set;
import java.util.regex.Matcher;

@Controller
public class SecureGreetingController {

    // Whitelist of allowed template names
    private static final Set<String> ALLOWED_TEMPLATES = Set.of(
        "home", "about", "contact", "greeting"
    );

    private static final Set<String> ALLOWED_FRAGMENTS = Set.of(
        "header", "footer", "sidebar", "content"
    );

    @GetMapping("/greeting")
    public String greeting(
            @RequestParam(name = "name") 
            @Pattern(regexp = "^[a-zA-Z0-9\\s]{1,50}$", message = "Invalid name") 
            String name, 
            Model model) {

        // SECURE: HTML-encode user input before adding to model
        String safeName = HtmlUtils.htmlEscape(name);
        model.addAttribute("greeting", safeName);
        return "greeting";
    }

    @GetMapping("/page")
    public String renderPage(@RequestParam(name = "template") String template) {
        // SECURE: Whitelist validation for template names
        if (!ALLOWED_TEMPLATES.contains(template)) {
            return "error/404";
        }
        return template;
    }

    @GetMapping("/fragment")
    public String fragment(@RequestParam(name = "section") String section, Model model) {
        // SECURE: Whitelist validation for fragments
        if (!ALLOWED_FRAGMENTS.contains(section)) {
            model.addAttribute("fragmentName", "default");
        } else {
            model.addAttribute("fragmentName", section);
        }
        return "layout";
    }
}
```

Secure Thymeleaf template (greeting.html):
```html
<!DOCTYPE html>
<html xmlns:th="http://www.thymeleaf.org">
<body>
    <!-- SECURE: th:text automatically escapes output -->
    <div th:text="'Hello, ' + ${greeting} + '!'"></div>

    <!-- SECURE: Static fragment references only -->
    <div th:replace="~{fragments/common :: header}"></div>

    <!-- SECURE: Conditional fragments with whitelist -->
    <div th:switch="${fragmentName}">
        <p th:case="'header'" th:replace="~{fragments/common :: header}"></p>
        <p th:case="'footer'" th:replace="~{fragments/common :: footer}"></p>
        <p th:case="*" th:replace="~{fragments/common :: default}"></p>
    </div>
</body>
</html>
```

**Key Security Controls**:
- **Input validation**: Use regex patterns to restrict input to expected characters only
- **Whitelist template names**: Never allow user input to directly control template selection
- **Use th:text not th:utext**: `th:text` automatically HTML-escapes content
- **Avoid preprocessing**: Never use `__${}__` syntax with user input
- **Static fragment references**: Use fragment references that don't involve user input

Dynamic content generation is a common requirement, but it must be implemented with multiple layers of protection. Here's a production-ready approach that separates user data from template logic.

**PRODUCTION PATTERN**:

```java
import org.springframework.stereotype.Service;
import org.springframework.web.bind.annotation.*;
import org.thymeleaf.TemplateEngine;
import org.thymeleaf.context.Context;
import org.thymeleaf.templateresolver.StringTemplateResolver;
import org.thymeleaf.templatemode.TemplateMode;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import javax.validation.Valid;
import javax.validation.constraints.*;
import java.util.*;
import java.util.regex.Pattern;

@Service
public class SecureTemplateService {

    private static final Logger auditLog = LoggerFactory.getLogger("SECURITY_AUDIT");
    private static final Logger logger = LoggerFactory.getLogger(SecureTemplateService.class);

    // Strict pattern for placeholder names
    private static final Pattern SAFE_PLACEHOLDER = Pattern.compile("^[a-zA-Z][a-zA-Z0-9_]{0,29}$");

    // Dangerous patterns to detect SSTI attempts
    private static final List<Pattern> SSTI_PATTERNS = Arrays.asList(
        Pattern.compile("\\$\\{.*\\}", Pattern.CASE_INSENSITIVE),
        Pattern.compile("__.*__"),
        Pattern.compile("T\\s*\\(", Pattern.CASE_INSENSITIVE),
        Pattern.compile("getClass\\s*\\(", Pattern.CASE_INSENSITIVE),
        Pattern.compile("getRuntime", Pattern.CASE_INSENSITIVE),
        Pattern.compile("ProcessBuilder", Pattern.CASE_INSENSITIVE),
        Pattern.compile("exec\\s*\\(", Pattern.CASE_INSENSITIVE),
        Pattern.compile("#\\{.*\\}"),
        Pattern.compile("@\\{.*\\}")
    );

    private final TemplateEngine restrictedEngine;
    private final Map<String, String> approvedTemplates;

    public SecureTemplateService() {
        this.restrictedEngine = createRestrictedEngine();
        this.approvedTemplates = loadApprovedTemplates();
    }

    private TemplateEngine createRestrictedEngine() {
        TemplateEngine engine = new TemplateEngine();
        StringTemplateResolver resolver = new StringTemplateResolver();

        // Use TEXT mode to prevent any expression evaluation
        resolver.setTemplateMode(TemplateMode.TEXT);
        resolver.setCacheable(true);

        engine.setTemplateResolver(resolver);
        return engine;
    }

    private Map<String, String> loadApprovedTemplates() {
        // Load pre-approved templates from secure storage
        Map<String, String> templates = new HashMap<>();
        templates.put("welcome_email", "Hello [[${userName}]], welcome to our service!");
        templates.put("order_confirm", "Order #[[${orderId}]] confirmed for [[${userName}]].");
        templates.put("password_reset", "Click here to reset password: [[${resetLink}]]");
        return Collections.unmodifiableMap(templates);
    }

    public String renderSecureTemplate(String templateId, Map<String, Object> variables, String userId) {
        // LAYER 1: Validate template ID against whitelist
        String template = approvedTemplates.get(templateId);
        if (template == null) {
            auditLog.warn("SSTI_ATTEMPT: Unknown template '{}' requested by user {}", 
                         templateId, userId);
            throw new SecurityException("Invalid template");
        }

        // LAYER 2: Validate and sanitize all variable values
        Map<String, Object> safeVariables = sanitizeVariables(variables, userId);

        // LAYER 3: Detect SSTI patterns in sanitized values (defense in depth)
        for (Object value : safeVariables.values()) {
            if (value instanceof String && containsSSTIPattern((String) value)) {
                auditLog.error("SSTI_BLOCKED: Malicious pattern in value for user {}", userId);
                throw new SecurityException("Invalid input detected");
            }
        }

        // LAYER 4: Render with restricted engine
        try {
            Context context = new Context();
            context.setVariables(safeVariables);
            return restrictedEngine.process(template, context);
        } catch (Exception e) {
            logger.error("Template rendering failed", e);
            throw new RuntimeException("Failed to render template");
        }
    }

    private Map<String, Object> sanitizeVariables(Map<String, Object> variables, String userId) {
        Map<String, Object> safe = new HashMap<>();

        for (Map.Entry<String, Object> entry : variables.entrySet()) {
            String key = entry.getKey();
            Object value = entry.getValue();

            // Validate key format
            if (!SAFE_PLACEHOLDER.matcher(key).matches()) {
                auditLog.warn("SSTI_ATTEMPT: Invalid placeholder name '{}' from user {}", 
                             key, userId);
                continue;
            }

            // Sanitize string values
            if (value instanceof String) {
                String strValue = (String) value;
                // Remove any potential template syntax
                strValue = strValue.replaceAll("[\\[\\]\\{\\}$#@_]", "");
                // Limit length
                if (strValue.length() > 500) {
                    strValue = strValue.substring(0, 500);
                }
                safe.put(key, strValue);
            } else if (value instanceof Number || value instanceof Boolean) {
                safe.put(key, value);
            }
            // Ignore complex objects - only primitives allowed
        }

        return safe;
    }

    private boolean containsSSTIPattern(String input) {
        for (Pattern pattern : SSTI_PATTERNS) {
            if (pattern.matcher(input).find()) {
                return true;
            }
        }
        return false;
    }
}

@RestController
@RequestMapping("/api/templates")
public class SecureTemplateController {

    private static final Logger auditLog = LoggerFactory.getLogger("SECURITY_AUDIT");

    private final SecureTemplateService templateService;
    private final RateLimiter rateLimiter;

    public SecureTemplateController(SecureTemplateService templateService) {
        this.templateService = templateService;
        this.rateLimiter = RateLimiter.create(10.0); // 10 requests per second
    }

    @PostMapping("/render")
    public ResponseEntity<String> renderTemplate(
            @Valid @RequestBody TemplateRequest request,
            @RequestHeader("X-User-ID") String userId,
            HttpServletRequest httpRequest) {

        // Rate limiting
        if (!rateLimiter.tryAcquire()) {
            auditLog.warn("RATE_LIMIT: Template render blocked for user {} from {}",
                         userId, httpRequest.getRemoteAddr());
            return ResponseEntity.status(429).body("Too many requests");
        }

        auditLog.info("TEMPLATE_RENDER: User {} rendering template '{}' from {}",
                     userId, request.getTemplateId(), httpRequest.getRemoteAddr());

        try {
            String result = templateService.renderSecureTemplate(
                request.getTemplateId(),
                request.getVariables(),
                userId
            );
            return ResponseEntity.ok(result);
        } catch (SecurityException e) {
            auditLog.error("SECURITY_VIOLATION: {} for user {} from {}",
                          e.getMessage(), userId, httpRequest.getRemoteAddr());
            return ResponseEntity.badRequest().body("Invalid request");
        }
    }
}

class TemplateRequest {
    @NotNull
    @Pattern(regexp = "^[a-z_]{1,30}$")
    private String templateId;

    @NotNull
    @Size(max = 20)
    private Map<String, Object> variables;

    // Getters and setters
    public String getTemplateId() { return templateId; }
    public void setTemplateId(String templateId) { this.templateId = templateId; }
    public Map<String, Object> getVariables() { return variables; }
    public void setVariables(Map<String, Object> variables) { this.variables = variables; }
}
```

**Spring Security Configuration**:

```java
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.web.SecurityFilterChain;
import org.springframework.security.web.header.writers.ContentSecurityPolicyHeaderWriter;

@Configuration
public class SecurityConfig {

    @Bean
    public SecurityFilterChain filterChain(HttpSecurity http) throws Exception {
        http
            .headers(headers -> headers
                // Prevent content sniffing
                .contentTypeOptions(contentType -> {})
                // XSS protection
                .xssProtection(xss -> xss.block(true))
                // CSP to prevent inline script execution
                .contentSecurityPolicy(csp -> csp
                    .policyDirectives("default-src 'self'; script-src 'self'; object-src 'none'"))
                // Prevent framing
                .frameOptions(frame -> frame.deny())
            )
            .csrf(csrf -> csrf.csrfTokenRepository(CookieCsrfTokenRepository.withHttpOnlyFalse()));

        return http.build();
    }
}
```

**Defense in Depth Layers**:

1. **Template Whitelisting**: Only pre-approved templates can be rendered
```java
// Templates stored in code/database, never from user input
String template = approvedTemplates.get(templateId);
if (template == null) throw new SecurityException("Invalid template");
```

2. **Input Sanitization**: All variable values are stripped of dangerous characters
```java
// Remove template syntax characters
strValue = strValue.replaceAll("[\\[\\]\\{\\}$#@_]", "");
// Only allow primitives, not complex objects
if (value instanceof String || value instanceof Number) {
    safe.put(key, sanitizedValue);
}
```

3. **SSTI Pattern Detection**: Block known attack patterns even after sanitization
```java
private static final List<Pattern> SSTI_PATTERNS = Arrays.asList(
    Pattern.compile("T\\s*\\("),  // SpEL type expressions
    Pattern.compile("getRuntime"),  // Runtime access
    Pattern.compile("__.*__")  // Preprocessing
);
```

4. **Restricted Template Engine**: Use TEXT mode to prevent expression evaluation
```java
resolver.setTemplateMode(TemplateMode.TEXT);
// Only simple [[${var}]] substitution, no SpEL
```

**Additional Protections**:
- **Rate limiting**: Prevent brute-force SSTI testing (10 req/sec)
- **Audit logging**: All template operations logged with user ID and IP
- **Security headers**: CSP prevents execution of injected scripts
- **Input length limits**: Variables capped at 500 characters
- **Fail secure**: Any error returns generic message, no stack traces
- **Separate audit logger**: Security events easily monitored via SIEM
- **Request validation**: Bean validation on all input DTOs

Server-Side Template Injection (SSTI) occurs when user input is embedded directly into template strings that get processed by the template engine. In Go, while the standard library templates have some protections, improper usage or third-party Mustache libraries can still be vulnerable.

**VULNERABLE CODE**:

```go
package main

import (
	"net/http"
	"github.com/cbroglie/mustache"
)

func renderTemplate(w http.ResponseWriter, r *http.Request) {
	// DANGEROUS: User input directly used as template
	userTemplate := r.URL.Query().Get("template")
	userName := r.URL.Query().Get("name")

	// Vulnerable: User controls the template structure
	data := map[string]interface{}{
		"name":    userName,
		"secret":  getSecretKey(),
		"config":  getServerConfig(),
		"dbCreds": getDatabaseCredentials(),
	}

	// User-controlled template can access ALL data in context
	output, err := mustache.Render(userTemplate, data)
	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}

	w.Write([]byte(output))
}

func getSecretKey() string {
	return "super-secret-api-key-12345"
}

func getServerConfig() map[string]string {
	return map[string]string{"env": "production", "debug": "false"}
}

func getDatabaseCredentials() map[string]string {
	return map[string]string{"host": "db.internal", "password": "db-secret-pwd"}
}
```

**Attack Payload**:
```text
?template={{secret}}%20{{#dbCreds}}{{host}}:{{password}}{{/dbCreds}}&name=attacker
```

**Why This Is Dangerous**:
- User controls the entire template structure, not just data values
- Attacker can enumerate and access all keys in the data context
- Sensitive information (secrets, credentials) exposed through template traversal
- In more powerful template engines, this can lead to Remote Code Execution

**SECURE VERSION**:

```go
package main

import (
	"net/http"
	"regexp"
	"strings"
	"github.com/cbroglie/mustache"
)

// Predefined safe templates - users cannot modify structure
var safeTemplates = map[string]string{
	"greeting":     "Hello, {{name}}! Welcome to our service.",
	"notification": "Dear {{name}}, you have {{count}} new messages.",
	"profile":      "User Profile: {{name}} - Member since {{joinDate}}",
}

// AllowedData contains ONLY safe, non-sensitive data
type AllowedData struct {
	Name     string
	Count    int
	JoinDate string
}

func renderTemplateSafe(w http.ResponseWriter, r *http.Request) {
	// User selects from predefined templates only
	templateID := r.URL.Query().Get("templateId")
	userName := r.URL.Query().Get("name")

	// Validate template ID exists in whitelist
	template, exists := safeTemplates[templateID]
	if !exists {
		http.Error(w, "Invalid template ID", http.StatusBadRequest)
		return
	}

	// Sanitize user input - prevent template injection in data
	sanitizedName := sanitizeInput(userName)

	// Only expose safe, non-sensitive data
	data := AllowedData{
		Name:     sanitizedName,
		Count:    5,
		JoinDate: "2024-01-15",
	}

	output, err := mustache.Render(template, data)
	if err != nil {
		http.Error(w, "Template rendering failed", http.StatusInternalServerError)
		return
	}

	w.Header().Set("Content-Type", "text/html; charset=utf-8")
	w.Write([]byte(output))
}

func sanitizeInput(input string) string {
	// Remove any potential template syntax from user input
	re := regexp.MustCompile(`[{}#^/&<>"']`)
	sanitized := re.ReplaceAllString(input, "")
	return strings.TrimSpace(sanitized)
}
```

**Key Security Controls**:
- **Template Whitelisting**: Users select from predefined template IDs, never control template structure
- **Data Isolation**: Only expose non-sensitive data through typed structs, secrets never in template context
- **Input Sanitization**: Remove template metacharacters from user-provided data values

When user-customizable templates are a legitimate business requirement, you need a sandboxed approach with strict controls. This is common in SaaS platforms offering custom email templates or report builders.

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"database/sql"
	"encoding/json"
	"errors"
	"fmt"
	"log/slog"
	"net/http"
	"regexp"
	"strings"
	"time"

	"github.com/cbroglie/mustache"
	"github.com/google/uuid"
	_ "github.com/lib/pq"
)

var (
	ErrInvalidTemplate    = errors.New("template contains forbidden patterns")
	ErrTemplateTimeout    = errors.New("template rendering timed out")
	ErrTemplateTooComplex = errors.New("template exceeds complexity limits")
)

// SafeTemplateEngine provides sandboxed template rendering
type SafeTemplateEngine struct {
	db            *sql.DB
	logger        *slog.Logger
	maxLength     int
	maxNesting    int
	allowedFields map[string]bool
	forbiddenPatterns []*regexp.Regexp
}

// TemplateRenderRequest represents a template render request
type TemplateRenderRequest struct {
	TemplateID string                 `json:"template_id"`
	Data       map[string]interface{} `json:"data"`
}

// AuditLog represents template activity
type AuditLog struct {
	ID         string    `json:"id"`
	UserID     string    `json:"user_id"`
	Action     string    `json:"action"`
	TemplateID string    `json:"template_id"`
	Timestamp  time.Time `json:"timestamp"`
	Success    bool      `json:"success"`
	IPAddress  string    `json:"ip_address"`
}

func NewSafeTemplateEngine(db *sql.DB, logger *slog.Logger) *SafeTemplateEngine {
	return &SafeTemplateEngine{
		db:         db,
		logger:     logger,
		maxLength:  10000, // 10KB max template size
		maxNesting: 3,     // Max 3 levels of nested sections
		allowedFields: map[string]bool{
			"user_name":    true,
			"email":        true,
			"company_name": true,
			"order_id":     true,
			"items":        true,
			"total":        true,
			"date":         true,
		},
		forbiddenPatterns: []*regexp.Regexp{
			regexp.MustCompile(`(?i)\{\{\s*[#^/]?\s*(password|secret|key|token|credential|auth|admin|config|env|system|exec|eval|import|require)`),
			regexp.MustCompile(`(?i)__proto__|constructor|prototype`),
			regexp.MustCompile(`(?i)\$\{|<%|%>|<\?`), // Other template syntaxes
		},
	}
}

// ValidateTemplate checks template for security issues before storage
func (e *SafeTemplateEngine) ValidateTemplate(template string) error {
	// Length check
	if len(template) > e.maxLength {
		return fmt.Errorf("%w: template exceeds %d characters", ErrTemplateTooComplex, e.maxLength)
	}

	// Check for forbidden patterns
	for _, pattern := range e.forbiddenPatterns {
		if pattern.MatchString(template) {
			return fmt.Errorf("%w: matches forbidden pattern", ErrInvalidTemplate)
		}
	}

	// Check nesting depth
	if e.countNestingDepth(template) > e.maxNesting {
		return fmt.Errorf("%w: nesting exceeds %d levels", ErrTemplateTooComplex, e.maxNesting)
	}

	// Validate all referenced fields are in allowlist
	fields := e.extractTemplateFields(template)
	for _, field := range fields {
		baseField := strings.Split(field, ".")[0]
		if !e.allowedFields[baseField] {
			return fmt.Errorf("%w: field '%s' not allowed", ErrInvalidTemplate, field)
		}
	}

	// Try to parse template to catch syntax errors
	_, err := mustache.ParseString(template)
	if err != nil {
		return fmt.Errorf("%w: %v", ErrInvalidTemplate, err)
	}

	return nil
}

func (e *SafeTemplateEngine) countNestingDepth(template string) int {
	maxDepth := 0
	currentDepth := 0
	sectionStart := regexp.MustCompile(`\{\{[#^]`)
	sectionEnd := regexp.MustCompile(`\{\{/`)

	for i := 0; i < len(template); {
		if loc := sectionStart.FindStringIndex(template[i:]); loc != nil && loc[0] == 0 {
			currentDepth++
			if currentDepth > maxDepth {
				maxDepth = currentDepth
			}
			i += 3
		} else if loc := sectionEnd.FindStringIndex(template[i:]); loc != nil && loc[0] == 0 {
			currentDepth--
			i += 3
		} else {
			i++
		}
	}
	return maxDepth
}

func (e *SafeTemplateEngine) extractTemplateFields(template string) []string {
	fieldPattern := regexp.MustCompile(`\{\{[#^/]?\s*([a-zA-Z_][a-zA-Z0-9_.]*)`)
	matches := fieldPattern.FindAllStringSubmatch(template, -1)

	fields := make([]string, 0, len(matches))
	seen := make(map[string]bool)

	for _, match := range matches {
		if len(match) > 1 && !seen[match[1]] {
			fields = append(fields, match[1])
			seen[match[1]] = true
		}
	}
	return fields
}

// RenderWithTimeout renders template with security controls
func (e *SafeTemplateEngine) RenderWithTimeout(ctx context.Context, templateContent string, data map[string]interface{}) (string, error) {
	// Create timeout context - prevent DoS via complex templates
	renderCtx, cancel := context.WithTimeout(ctx, 5*time.Second)
	defer cancel()

	resultChan := make(chan string, 1)
	errorChan := make(chan error, 1)

	go func() {
		// Filter data to only allowed fields
		filteredData := e.filterData(data)

		output, err := mustache.Render(templateContent, filteredData)
		if err != nil {
			errorChan <- err
			return
		}
		resultChan <- output
	}()

	select {
	case <-renderCtx.Done():
		return "", ErrTemplateTimeout
	case err := <-errorChan:
		return "", err
	case result := <-resultChan:
		return result, nil
	}
}

func (e *SafeTemplateEngine) filterData(data map[string]interface{}) map[string]interface{} {
	filtered := make(map[string]interface{})
	for key, value := range data {
		if e.allowedFields[key] {
			filtered[key] = value
		}
	}
	return filtered
}

// HTTP Handler with full security controls
func (e *SafeTemplateEngine) HandleRender(w http.ResponseWriter, r *http.Request) {
	requestID := uuid.New().String()
	userID := r.Header.Get("X-User-ID")
	ipAddress := r.RemoteAddr

	e.logger.Info("template render request",
		"request_id", requestID,
		"user_id", userID,
		"ip", ipAddress,
	)

	var req TemplateRenderRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		e.logAudit(userID, "render_failed", req.TemplateID, false, ipAddress)
		http.Error(w, "Invalid request", http.StatusBadRequest)
		return
	}

	// Fetch template from database (not user input)
	templateContent, err := e.getTemplateFromDB(req.TemplateID, userID)
	if err != nil {
		e.logAudit(userID, "render_failed", req.TemplateID, false, ipAddress)
		http.Error(w, "Template not found", http.StatusNotFound)
		return
	}

	// Render with timeout and filtered data
	output, err := e.RenderWithTimeout(r.Context(), templateContent, req.Data)
	if err != nil {
		e.logger.Error("template render failed",
			"request_id", requestID,
			"error", err.Error(),
		)
		e.logAudit(userID, "render_failed", req.TemplateID, false, ipAddress)
		http.Error(w, "Rendering failed", http.StatusInternalServerError)
		return
	}

	e.logAudit(userID, "render_success", req.TemplateID, true, ipAddress)

	w.Header().Set("Content-Type", "text/html; charset=utf-8")
	w.Header().Set("X-Content-Type-Options", "nosniff")
	w.Header().Set("X-Request-ID", requestID)
	w.Write([]byte(output))
}

func (e *SafeTemplateEngine) getTemplateFromDB(templateID, userID string) (string, error) {
	var content string
	err := e.db.QueryRow(
		`SELECT content FROM templates 
		 WHERE id = $1 AND (user_id = $2 OR is_public = true) AND is_approved = true`,
		templateID, userID,
	).Scan(&content)
	return content, err
}

func (e *SafeTemplateEngine) logAudit(userID, action, templateID string, success bool, ipAddress string) {
	_, err := e.db.Exec(
		`INSERT INTO template_audit_log (id, user_id, action, template_id, timestamp, success, ip_address)
		 VALUES ($1, $2, $3, $4, $5, $6, $7)`,
		uuid.New().String(), userID, action, templateID, time.Now(), success, ipAddress,
	)
	if err != nil {
		e.logger.Error("audit log failed", "error", err.Error())
	}
}
```

**Defense in Depth Layers**:

1. **Template Validation at Storage Time**:
```go
func (e *SafeTemplateEngine) SaveTemplate(userID, content string) (string, error) {
    // Validate BEFORE storing
    if err := e.ValidateTemplate(content); err != nil {
        return "", err
    }

    // Require admin approval for new templates
    templateID := uuid.New().String()
    _, err := e.db.Exec(
        `INSERT INTO templates (id, user_id, content, is_approved, created_at)
         VALUES ($1, $2, $3, false, $4)`,
        templateID, userID, content, time.Now(),
    )
    return templateID, err
}
```

2. **Runtime Data Isolation**:
```go
