No, regex-based filtering is fundamentally insufficient against XSS attacks, especially polyglot payloads that are designed to bypass multiple sanitization methods simultaneously. A polyglot XSS payload works across different parsing contexts (HTML, JavaScript, CSS, SVG) making single-layer regex defenses completely ineffective.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const app = express();

app.use(express.json());
app.use(express.urlencoded({ extended: true }));

// VULNERABLE: Regex-based XSS filtering
function sanitizeComment(input) {
  // Naive attempt to filter script tags
  let sanitized = input.replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '');

  // Try to filter event handlers
  sanitized = sanitized.replace(/on\w+\s*=/gi, '');

  // Attempt to filter javascript: URLs
  sanitized = sanitized.replace(/javascript:/gi, '');

  return sanitized;
}

app.post('/api/comments', (req, res) => {
  const { comment } = req.body;
  const sanitizedComment = sanitizeComment(comment);

  // Store and render - STILL VULNERABLE
  res.send(`<div class="comment">${sanitizedComment}</div>`);
});

app.listen(3000);
```

**Attack Payload** (Polyglot XSS):
```html
jaVasCript:/*-/*`/*\`/*'/*"/**/(/* */oNcLiCk=alert() )//%0D%0A%0d%0a//</stYle/</titLe/</teXtarEa/</scRipt/--!>\x3csVg/<sVg/oNloAd=alert()//>\x3e
