// Advanced mXSS-resistant sanitization
class SecureHTMLSanitizer {
  constructor() {
    this.domPurifyConfig = {
      ALLOWED_TAGS: ['b', 'i', 'em', 'strong', 'a', 'p', 'br', 'ul', 'ol', 'li', 'blockquote', 'code'],
      ALLOWED_ATTR: ['href', 'title', 'rel'],
      ALLOW_DATA_ATTR: false,
      FORBID_TAGS: ['style', 'script', 'svg', 'math', 'iframe', 'object', 'embed', 'template', 'noscript', 'xmp', 'plaintext'],
      FORBID_ATTR: ['style', 'id', 'class'],
      WHOLE_DOCUMENT: false,
      RETURN_DOM: false,
      RETURN_DOM_FRAGMENT: false,
      RETURN_TRUSTED_TYPE: false,
      FORCE_BODY: true,
      SANITIZE_DOM: true,
      KEEP_CONTENT: true,
      IN_PLACE: false
    };

    // Add hooks to catch mXSS attempts
    DOMPurify.addHook('uponSanitizeElement', (node, data) => {
      // Log suspicious elements that might indicate mXSS attempt
      if (data.tagName && ['noscript', 'template', 'svg', 'math'].includes(data.tagName.toLowerCase())) {
        logger.warn('Potential mXSS attempt detected', {
          tagName: data.tagName,
          timestamp: new Date().toISOString()
        });
      }
    });

    DOMPurify.addHook('afterSanitizeAttributes', (node) => {
      // Force target="_blank" links to have rel="noopener"
      if (node.tagName === 'A' && node.getAttribute('target') === '_blank') {
        node.setAttribute('rel', 'noopener noreferrer');
      }

      // Validate href is not malicious
      if (node.hasAttribute('href')) {
        const href = node.getAttribute('href');
        if (!this.isValidHref(href)) {
          node.removeAttribute('href');
          logger.warn('Malicious href removed', { href });
        }
      }
    });
  }

  isValidHref(href) {
    if (!href) return false;

    // Only allow http, https, and relative URLs
    const allowedProtocols = ['http:', 'https:', 'mailto:'];

    try {
      // Handle relative URLs
      if (href.startsWith('/') || href.startsWith('#')) {
        return true;
      }

      const url = new URL(href);
      return allowedProtocols.includes(url.protocol);
    } catch {
      // If URL parsing fails, it might be relative or malformed
      // Reject anything that looks like a protocol
      return !href.includes(':') || href.startsWith('//');
    }
  }

  sanitize(input) {
    if (!input || typeof input !== 'string') {
      return '';
    }

    // Pre-sanitization normalization to defeat encoding tricks
    const normalized = this.normalizeInput(input);

    // First pass sanitization
    let sanitized = DOMPurify.sanitize(normalized, this.domPurifyConfig);

    // CRITICAL: Double sanitize to catch mXSS
    // Browser mutation can occur between first parse and re-serialization
    sanitized = DOMPurify.sanitize(sanitized, this.domPurifyConfig);

    // Post-sanitization validation
    if (this.containsSuspiciousPatterns(sanitized)) {
      logger.error('Post-sanitization check failed', {
        originalLength: input.length,
        sanitizedLength: sanitized.length
      });
      return '';
    }

    return sanitized;
  }

  normalizeInput(input) {
    // Decode common encoding tricks
    let normalized = input;

    // Remove null bytes
    normalized = normalized.replace(/\x00/g, '');

    // Normalize unicode
    normalized = normalized.normalize('NFC');

    return normalized;
  }

  containsSuspiciousPatterns(html) {
    // Check for patterns that survived sanitization but look dangerous
    const suspiciousPatterns = [
      /javascript\s*:/i,
      /vbscript\s*:/i,
      /data\s*:/i,
      /expression\s*\(/i,
      /-moz-binding/i,
      /behavior\s*:/i
    ];

    return suspiciousPatterns.some(pattern => pattern.test(html));
  }
}

