When you need to allow selective HTML in markdown, you must implement a strict allowlist approach with multiple defensive layers. This is a high-risk pattern that requires careful implementation.

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"crypto/sha256"
	"encoding/hex"
	"log"
	"net/http"
	"regexp"
	"strings"
	"time"

	"github.com/gomarkdown/markdown"
	"github.com/gomarkdown/markdown/html"
	"github.com/gomarkdown/markdown/parser"
	"github.com/microcosm-cc/bluemonday"
	"github.com/redis/go-redis/v9"
)

type MarkdownRenderer struct {
	policy       *bluemonday.Policy
	cache        *redis.Client
	logger       *log.Logger
	maxInputSize int
}

func NewSecureMarkdownRenderer(redisClient *redis.Client, logger *log.Logger) *MarkdownRenderer {
	// Create strict allowlist policy
	policy := bluemonday.NewPolicy()

	// Allow basic formatting
	policy.AllowElements("p", "br", "hr")
	policy.AllowElements("h1", "h2", "h3", "h4", "h5", "h6")
	policy.AllowElements("strong", "em", "b", "i", "u", "s", "strike")
	policy.AllowElements("ul", "ol", "li")
	policy.AllowElements("blockquote")

	// Allow code blocks with syntax highlighting
	policy.AllowElements("pre", "code")
	policy.AllowAttrs("class").Matching(regexp.MustCompile(`^language-[a-zA-Z0-9_-]+$`)).OnElements("code")

	// Allow tables
	policy.AllowElements("table", "thead", "tbody", "tr", "th", "td")

	// Allow images with strict URL validation
	policy.AllowImages()
	policy.AllowAttrs("src").Matching(regexp.MustCompile(`^https://[a-zA-Z0-9][a-zA-Z0-9.-]+\.[a-zA-Z]{2,}/`)).OnElements("img")
	policy.AllowAttrs("alt", "title").OnElements("img")

	// Allow links with strict URL validation
	policy.AllowAttrs("href").Matching(regexp.MustCompile(`^https?://[a-zA-Z0-9]`)).OnElements("a")
	policy.AllowAttrs("title").OnElements("a")
	policy.RequireNoReferrerOnLinks(true)
	policy.AddTargetBlankToFullyQualifiedLinks(true)

	// EXPLICITLY BLOCK dangerous patterns
	policy.AllowNoAttrs().OnElements("script", "style", "iframe", "object", "embed")

	return &MarkdownRenderer{
		policy:       policy,
		cache:        redisClient,
		logger:       logger,
		maxInputSize: 100000, // 100KB max
	}
}

func (mr *MarkdownRenderer) RenderSecure(ctx context.Context, userContent string, userID string) ([]byte, error) {
	// Input validation
	if len(userContent) > mr.maxInputSize {
		mr.logger.Printf("SECURITY: Input size exceeded for user %s: %d bytes", userID, len(userContent))
		return nil, ErrInputTooLarge
	}

	// Check for suspicious patterns (logging only, don't block)
	mr.detectSuspiciousPatterns(userContent, userID)

	// Check cache for already-rendered content
	contentHash := mr.hashContent(userContent)
	cacheKey := "md:" + contentHash

	if cached, err := mr.cache.Get(ctx, cacheKey).Bytes(); err == nil {
		mr.logger.Printf("Cache hit for content hash: %s", contentHash[:16])
		return cached, nil
	}

	// Step 1: Pre-process to neutralize dangerous patterns
	sanitizedInput := mr.preProcess(userContent)

	// Step 2: Parse markdown
	extensions := parser.CommonExtensions | parser.AutoHeadingIDs | parser.NoEmptyLineBeforeBlock
	p := parser.NewWithExtensions(extensions)

	// Step 3: Render with restricted HTML
	htmlFlags := html.CommonFlags | html.HrefTargetBlank
	opts := html.RendererOptions{Flags: htmlFlags}
	renderer := html.NewRenderer(opts)

	rawHTML := markdown.ToHTML([]byte(sanitizedInput), p, renderer)

	// Step 4: Sanitize output with strict policy
	safeHTML := mr.policy.SanitizeBytes(rawHTML)

	// Step 5: Post-process validation
	if !mr.validateOutput(safeHTML) {
		mr.logger.Printf("SECURITY: Output validation failed for user %s, hash: %s", userID, contentHash[:16])
		return nil, ErrOutputValidationFailed
	}

	// Cache for 1 hour
	mr.cache.Set(ctx, cacheKey, safeHTML, time.Hour)

	return safeHTML, nil
}

func (mr *MarkdownRenderer) preProcess(content string) string {
	// Remove null bytes and control characters
	content = strings.Map(func(r rune) rune {
		if r == 0 || (r < 32 && r != '\n' && r != '\r' && r != '\t') {
			return -1
		}
		return r
	}, content)

	// Neutralize javascript: URLs
	jsPattern := regexp.MustCompile(`(?i)javascript\s*:`)
	content = jsPattern.ReplaceAllString(content, "blocked:")

	// Neutralize data: URLs (potential XSS vector)
	dataPattern := regexp.MustCompile(`(?i)data\s*:`)
	content = dataPattern.ReplaceAllString(content, "blocked:")

	// Neutralize vbscript: URLs
	vbPattern := regexp.MustCompile(`(?i)vbscript\s*:`)
	content = vbPattern.ReplaceAllString(content, "blocked:")

	return content
}

func (mr *MarkdownRenderer) detectSuspiciousPatterns(content string, userID string) {
	suspiciousPatterns := []struct {
		pattern *regexp.Regexp
		name    string
	}{
		{regexp.MustCompile(`(?i)<script`), "script_tag"},
		{regexp.MustCompile(`(?i)on\w+\s*=`), "event_handler"},
		{regexp.MustCompile(`(?i)javascript:`), "javascript_url"},
		{regexp.MustCompile(`(?i)<iframe`), "iframe_tag"},
		{regexp.MustCompile(`(?i)expression\s*\(`), "css_expression"},
		{regexp.MustCompile(`(?i)@import`), "css_import"},
	}

	for _, sp := range suspiciousPatterns {
		if sp.pattern.MatchString(content) {
			mr.logger.Printf("SECURITY_ALERT: Suspicious pattern '%s' detected from user %s", sp.name, userID)
		}
	}
}

func (mr *MarkdownRenderer) validateOutput(html []byte) bool {
	htmlStr := string(html)

	// Final validation - these should never appear in output
	dangerousPatterns := []string{
		"<script",
		"javascript:",
		"onerror=",
		"onclick=",
		"onload=",
		"onmouseover=",
	}

	for _, pattern := range dangerousPatterns {
		if strings.Contains(strings.ToLower(htmlStr), pattern) {
			return false
		}
	}

	return true
}

func (mr *MarkdownRenderer) hashContent(content string) string {
	hash := sha256.Sum256([]byte(content))
	return hex.EncodeToString(hash[:])
}

var (
	ErrInputTooLarge         = &RenderError{Code: "INPUT_TOO_LARGE", Message: "Content exceeds maximum size"}
	ErrOutputValidationFailed = &RenderError{Code: "VALIDATION_FAILED", Message: "Content failed security validation"}
)

type RenderError struct {
	Code    string
	Message string
}

func (e *RenderError) Error() string {
	return e.Message
}

// HTTP Handler with security headers
func (mr *MarkdownRenderer) HandleRender(w http.ResponseWriter, r *http.Request) {
	ctx := r.Context()
	userID := r.Header.Get("X-User-ID")
	if userID == "" {
		userID = "anonymous"
	}

	content := r.FormValue("content")

	safeHTML, err := mr.RenderSecure(ctx, content, userID)
	if err != nil {
		mr.logger.Printf("Render error for user %s: %v", userID, err)
		http.Error(w, "Failed to render content", http.StatusBadRequest)
		return
	}

	// Security headers
	w.Header().Set("Content-Type", "text/html; charset=utf-8")
	w.Header().Set("X-Content-Type-Options", "nosniff")
	w.Header().Set("X-Frame-Options", "DENY")
	w.Header().Set("Content-Security-Policy", "default-src 'self'; script-src 'none'; style-src 'self' 'unsafe-inline'; img-src 'self' https:; frame-ancestors 'none'")
	w.Header().Set("Referrer-Policy", "strict-origin-when-cross-origin")

	w.Write(safeHTML)
}
```

**Defense in Depth Layers**:

1. **Input Pre-processing**: Neutralizes dangerous URL schemes before markdown parsing
```go
// Neutralize javascript: URLs before they reach the parser
jsPattern := regexp.MustCompile(`(?i)javascript\s*:`)
content = jsPattern.ReplaceAllString(content, "blocked:")
```

2. **Strict Allowlist Sanitization**: Only explicitly allowed elements and attributes pass through
```go
// Only allow class attributes matching safe patterns
policy.AllowAttrs("class").Matching(regexp.MustCompile(`^language-[a-zA-Z0-9_-]+$`)).OnElements("code")
```

3. **Output Validation**: Final check ensures no dangerous patterns exist in output
```go
for _, pattern := range dangerousPatterns {
    if strings.Contains(strings.ToLower(htmlStr), pattern) {
        return false
    }
}
```

**Additional Protections**:
- Content-Security-Policy header with `script-src 'none'` blocks script execution even if XSS bypasses sanitization
- Input size limits prevent DoS via large payloads
- Suspicious pattern detection enables security monitoring without blocking legitimate use
- Content hashing and caching prevents repeated processing of malicious content
- Per-user logging enables incident response and pattern analysis
- Redis caching improves performance while maintaining security audit trail
